// Poll the vault every interval and trigger the agent that owns any folder where
// a new "open" note appeared. Replaces the old localFileTrigger approach, which
// depended on the Local File Trigger node (unavailable in this n8n image, shows
// as "?") and on inotify seeing subfolders. This uses only fs + a schedule, the
// same proven pattern as the reminder scheduler.
//
// Dedup: workflow static data remembers, per note, the content hash we last
// fired on. We fire once per distinct content. When the agent flips status to
// "doing"/"done" the content changes AND it is no longer "open", so it is never
// re-triggered; and an unchanged still-"open" note is not spammed every poll.
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const ROOT = '/data/vault';
const DEFAULT_ROUTES = {
  assistant:  { port: 8642, model: 'deepseek/deepseek-v2-flash', folder: 'scratchpads' },
  engineer:   { port: 8643, model: 'anthropic/claude-opus-4-8', folder: 'projects' },
  researcher: { port: 8644, model: 'z-ai/glm-4.6', folder: 'memory' },
};
let routes = DEFAULT_ROUTES;
try { if ($env.GHIATH_ROUTES) routes = JSON.parse($env.GHIATH_ROUTES); } catch (e) {}

const agentByFolder = {};
for (const [name, cfg] of Object.entries(routes)) { if (cfg.folder) agentByFolder[cfg.folder] = name; }
const folders = Object.keys(agentByFolder);
if (!folders.length) return [];

const store = $getWorkflowStaticData('global');
const fired = store.fired || (store.fired = {});

const out = [];
const seen = new Set();

for (const folder of folders) {
  const dir = path.join(ROOT, folder);
  let files = [];
  try { files = fs.readdirSync(dir).filter((f) => f.endsWith('.md')); } catch (e) { continue; }

  for (const f of files) {
    const key = folder + '/' + f;
    seen.add(key);
    const fp = path.join(dir, f);
    let raw;
    try { raw = fs.readFileSync(fp, 'utf8'); } catch (e) { continue; }

    let status = 'open'; // notes without front-matter are human-created open tasks
    const fm = raw.match(/^---\n([\s\S]*?)\n---/);
    if (fm) {
      const s = fm[1].match(/^status:\s*(\S+)/m);
      if (s) status = s[1].toLowerCase();
    }
    if (status !== 'open') continue;

    const hash = crypto.createHash('sha256').update(raw).digest('hex');
    if (fired[key] === hash) continue; // already fired for this exact content
    fired[key] = hash;

    const agent = agentByFolder[folder];
    const r = routes[agent];
    const url = 'http://host.docker.internal:' + r.port + '/v1/chat/completions';
    const hostPath = key;
    const prompt =
      'An open note was placed in your folder: ' + hostPath +
      '\nRead it, set its status to "doing", act on it, then set its status to "done". ' +
      'Record your result as a note with type "result", status "done", owner yourself. ' +
      'If the task should move to another agent, drop an "open" note in that agent\'s folder with owner set to them.';

    out.push({ json: { agent, folder, url, model: r.model, prompt, note: hostPath } });
  }
}

// Forget notes that no longer exist so the map cannot grow forever.
for (const k of Object.keys(fired)) { if (!seen.has(k)) delete fired[k]; }

return out;
